const boundary = 'divider';
const docName = $input.first().json.document_name;
const folderId = $input.first().json.drive_folder_id;
const htmlContent = $input.first().json.html_content;

const metadata = JSON.stringify({
  name: docName,
  mimeType: "application/vnd.google-apps.document",
  parents: [folderId]
});

const htmlWithStyles = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    /* Add bottom margin to block elements for spacing */
    p,
    ul,
    ol,
    table,
    h1,
    h2,
    h3,
    h4,
    h5,
    h6 {
      margin-bottom: 10pt;
    }

    h2 {
      margin-top: 20pt;
    }

    /* Prevent margin collapse issues or excessive space inside lists */
    li {
       margin-bottom: 2pt; /* Optional: small space between list items */
    }

    /* Remove margin from the last child within common containers if needed */
    /* This might be overly aggressive, test without it first */
    /*
    body > *:last-child,
    li > *:last-child {
       margin-bottom: 0;
    }
    */
  </style>
</head>
<body>
  ${htmlContent}
</body>
</html>
`;

// Construct the body with literal \r\n ONLY
let body = `--${boundary}\r\n`;
body += `Content-Type: application/json; charset=UTF-8\r\n`;
body += `\r\n`; // Blank line
body += `${metadata}\r\n`;
body += `--${boundary}\r\n`;
body += `Content-Type: text/html\r\n`;
body += `\r\n`; // Blank line
body += `${htmlWithStyles}\r\n`; // Add the HTML content
body += `--${boundary}--\r\n`; // Final boundary

return {
  rawData: body 
};

// Extract Compliance Status for Branching
// Extracts PASS or FAIL from "**Overall Status:** PASS/FAIL"
// Also extracts violation count if present

const item = $input.first();
const output = item.json.output || '';

// Look for "**Overall Status:** PASS" or "**Overall Status:** FAIL"
const statusMatch = output.match(/\*\*Overall Status:\*\*\s*(PASS|FAIL)/i);

if (!statusMatch) {
  console.error('❌ Could not find Overall Status in output');
  console.log('Output preview:', output.substring(0, 200));

  // Default to FAIL if status cannot be determined
  return [{
    json: {
      status: 'FAIL',
      error: 'Could not parse status from Compliance output',
      raw_output: output
    }
  }];
}

const status = statusMatch[1].toUpperCase(); // Ensure uppercase

// Optionally extract violation count (useful for logging/debugging)
let violationCount = 0;
const violationMatch = output.match(/\*\*Violations Found:\*\*\s*(\d+)/i);
if (violationMatch) {
  violationCount = parseInt(violationMatch[1]);
}

console.log(`✅ Extracted status: ${status}`);
if (violationCount > 0) {
  console.log(`   Violations found: ${violationCount}`);
}

return [{
  json: {
    status: status,
    violation_count: violationCount,
    raw_output: output
  }
}];

const rawOutput = $input.item.json.output;

// Get target length — handle both numeric input and 'keep_original'
let targetLength = 2000;
try {
  const writerVars = $('Writer Variables').first().json;
  const rawTarget = writerVars.campaignContent.targetLength;

  if (rawTarget === 'keep_original') {
    targetLength = writerVars.advertorialUrl.word_count || 2000;
  } else {
    targetLength = parseInt(rawTarget) || 2000;
  }
} catch (e) {
  // Keep fallback
}

// Calculate acceptable range (±10% tolerance)
const minWords = Math.floor(targetLength * 0.90);
const maxWords = Math.ceil(targetLength * 1.10);

// Function to extract advertorial content (remove AI preamble if present)
function extractAdvertorial(text) {
  const hrSplit = text.split(/\n---+\n/);
  if (hrSplit.length > 1) {
    const firstPart = hrSplit[0];
    const metaPhrases = /ready to write|i'll craft|i will craft|based on my research|let me write|here's what i'll/i;
    if (metaPhrases.test(firstPart) && firstPart.length < 1000) {
      return hrSplit.slice(1).join('\n---\n').trim();
    }
  }

  const lines = text.split('\n');
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (/^#\s+/.test(line)) {
      const metaHeadings = /ready to write|i'll craft|i will craft|based on|let me|here's what/i;
      if (!metaHeadings.test(line)) {
        return lines.slice(i).join('\n').trim();
      }
    }
  }

  return text.trim();
}

// Function to count words (excludes placeholders from count)
function countWords(text) {
  let countableText = text;

  countableText = countableText.replace(/\*\*Placeholder for Image.*?\*\*/gi, '');
  countableText = countableText.replace(/\*USER NOTE:.*?\*/gi, '');
  countableText = countableText.replace(/\[IMAGE:[^\]]+\]/gi, '');
  countableText = countableText.replace(/\[PRODUCT WIDGET:[^\]]+\]/gi, '');
  countableText = countableText.replace(/\[VIDEO:[^\]]+\]/gi, '');
  countableText = countableText.replace(/\[CTA BUTTON:[^\]]+\]/gi, '');
  countableText = countableText.replace(/\[CHART:[^\]]+\]/gi, '');

  countableText = countableText.replace(/^#+\s+/gm, '');
  countableText = countableText
    .replace(/\*\*(.+?)\*\*/g, '$1')
    .replace(/\*(.+?)\*/g, '$1')
    .replace(/`(.+?)`/g, '$1')
    .replace(/\[(.+?)\]\(.+?\)/g, '$1');

  return countableText.trim().split(/\s+/).filter(word => word.length > 0).length;
}

// Calculate delta for over/under reporting
function getDelta(wordCount, minWords, maxWords, targetLength) {
  if (wordCount < minWords) {
    const wordsShort = targetLength - wordCount;
    const pctUnder = ((wordsShort / targetLength) * 100).toFixed(1);
    return { direction: 'under', words: wordsShort, percentage: pctUnder };
  } else if (wordCount > maxWords) {
    const wordsOver = wordCount - targetLength;
    const pctOver = ((wordsOver / targetLength) * 100).toFixed(1);
    return { direction: 'over', words: wordsOver, percentage: pctOver };
  }
  return { direction: 'within', words: 0, percentage: '0.0' };
}

// Execute
const cleanContent = extractAdvertorial(rawOutput);
const wordCount = countWords(cleanContent);
const meetsRequirements = wordCount >= minWords && wordCount <= maxWords;
const delta = getDelta(wordCount, minWords, maxWords, targetLength);

return {
  json: {
    raw_output: rawOutput,
    clean_content: cleanContent,

    word_count: wordCount,
    target_length: targetLength,
    min_words: minWords,
    max_words: maxWords,
    meets_requirements: meetsRequirements,

    delta_direction: delta.direction,
    delta_words: delta.words,
    delta_percentage: delta.percentage,
    word_count_status: meetsRequirements ? 'PASS' : 'FAIL',

    counted_at: new Date().toISOString()
  }
};

// Code Node: "Parse Sanity Result"

const output = $input.item.json.output;
const status = output.startsWith('PASS') ? 'PASS' : 'FAIL';

return {
  json: {
    status: status,
    details: output
  }
};

// Code Node: "Mock Lazy Mode Webhook Data"

return {
  json: {
    headers: {
      "content-type": "application/json"
    },
    params: {},
    query: {},
    body: {
      campaignId: "a1b2c3d4-5678-9abc-def0-1234567890ab",
      instructions: "Rewrite this advertorial to target men aged 30-55 instead of women. Change all references to female hair loss patterns to male pattern baldness. Replace the testimonials with male names and experiences. Adjust the emotional angle from 'confidence and beauty' to 'looking younger and professional'. Keep the overall structure and flow the same, but make the first-person story about a man noticing thinning hair at work. The product benefits and science sections can stay mostly the same since the ingredients work for both genders, but frame the urgency around receding hairlines rather than thinning ponytails.",
      advertorialUrl: "https://www.womenshealthmag.com/beauty/a68041028/hair-loss-treatments-women/",
      additionalLinks: [
        {
          url: "https://www.healthline.com/health/male-pattern-baldness",
          description: "Use this as a reference for male-specific hair loss facts, statistics, and terminology to make the rewrite authentic."
        }
      ],
      referenceUrls: [
        {
          url: "https://www.womenshealthmag.com/beauty/a68041028/hair-loss-treatments-women/",
          description: "Reference advertorial"
        },
        {
          url: "https://www.healthline.com/health/male-pattern-baldness",
          description: "Use this as a reference for male-specific hair loss facts, statistics, and terminology to make the rewrite authentic."
        }
      ],
      campaignType: "Lead Generation",
      niche: "Beauty",
      country: "United States",
      language: "English",
      length: "keep_original",
      paragraphLength: "Short (1-3 lines)",
      guidelines: "Custom",
      customGuidelines: "Don't promise hair regrowth or use the word 'cure'. Always say 'may help' or 'designed to support'. Include a disclaimer that individual results vary. Don't bash competitors like Rogaine or Keeps by name."
    },
    webhookUrl: "https://manglarmedia.app.n8n.cloud/webhook/YOUR_LAZY_MODE_WEBHOOK_ID",
    executionMode: "production"
  }
};

const text = $input.first().json.output;

// Strip markdown formatting before counting
const stripped = text
  .replace(/#{1,6}\s/g, '')           // headings
  .replace(/\*\*?(.*?)\*\*?/g, '$1') // bold/italic
  .replace(/~~(.*?)~~/g, '$1')        // strikethrough
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1') // markdown links → keep anchor text
  .replace(/\[IMAGE:[^\]]+\]/g, '')   // image placeholders
  .replace(/\[VIDEO:[^\]]+\]/g, '')   // video placeholders
  .replace(/\[CHART:[^\]]+\]/g, '')   // chart placeholders
  .replace(/\[CTA BUTTON:[^\]]+\]/g, '')
  .replace(/\[PRODUCT WIDGET:[^\]]+\]/g, '')
  .replace(/[-*_]{3,}/g, '')          // horizontal rules
  .replace(/\n+/g, ' ')              // newlines to spaces
  .trim();

const wordCount = stripped
  .split(/\s+/)
  .filter(word => word.length > 0).length;

return {
  output: text,        // pass original content through
  word_count: wordCount
};

const data = $input.first().json;
const urls = data.scrapedUrls;

const advertorialUrl = urls.find(u => u.description === "Reference advertorial") || null;
const referenceUrls = urls.filter(u => u.description !== "Reference advertorial");

return {
  advertorialUrl,
  referenceUrls
};

// Get AI extracted topic from Topic Extractor (immediate input)
const aiTopic = $input.first().json.output || 'Advertorial';

// Get campaign context and advertorial content from Set node
const campaignContext = $('Content + context').first().json.campaignContext;
const advertorialContent = $('Content + context').first().json.advertorialContent;

// Campaign type abbreviation
const campaignTypeMap = {
  'Lead Generation': 'LEAD',
  'E-commerce': 'ECOM',
  'ecommerce': 'ECOM'
};
const campaignType = campaignTypeMap[campaignContext.campaignType] || 'DRAFT';

// Country to ISO code
const countryMap = {
  'United States': 'US',
  'United Kingdom': 'UK',
  'Canada': 'CA',
  'Germany': 'DE',
  'France': 'FR',
  'Spain': 'ES',
  'Italy': 'IT',
  'Netherlands': 'NL',
  'Australia': 'AU'
};
const country = countryMap[campaignContext.country] || 'XX';

// Date (dd.mm.yyyy)
const now = new Date();
const day = String(now.getDate()).padStart(2, '0');
const month = String(now.getMonth() + 1).padStart(2, '0');
const year = now.getFullYear();
const date = `${day}.${month}.${year}`;

// Build filename
const documentName = `${campaignType} - ${aiTopic} - ${country} - ${date}`;

console.log('📄 Generated filename:', documentName);

return {
  json: {
    documentName,
    aiExtractedTopic: aiTopic,
    advertorialContent
  }
};

const rawOutput = $input.first().json.output;

function extractAdvertorial(text) {
  // Strategy 1: Split on horizontal rule
  const hrSplit = text.split(/\n---+\n/);
  if (hrSplit.length > 1) {
    const firstPart = hrSplit[0];
    const metaPhrases = /ready to write|i'll craft|i will craft|based on my research|let me write|here's what i'll|the tool result|task is straightforward|trim|tighten|i have enough context/i;
    if (metaPhrases.test(firstPart) && firstPart.length < 1000) {
      return hrSplit.slice(1).join('\n---\n').trim();
    }
  }

  // Strategy 2: Find first real heading
  const lines = text.split('\n');
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (/^#\s+/.test(line)) {
      const metaHeadings = /ready to write|i'll craft|i will craft|based on|let me|here's what/i;
      if (!metaHeadings.test(line)) {
        return lines.slice(i).join('\n').trim();
      }
    }
  }

  return text.trim();
}

const cleanContent = extractAdvertorial(rawOutput);

return {
  json: {
    output: cleanContent
  }
};
